/* Overriding:
EndUser.prototype.func_name = (function(_super) {
	return function() {
		return _super.apply(this, arguments);
	};
})(EndUser.prototype.func_name);
*/

//-------------------------------------------------------------------------------

EndUser.prototype.ParseCertificateEx = (function (_super) {
	return function (cert, onSuccess, onError) {
		if (typeof (_super) === "function") {
			return _super.apply(this, arguments);
		}

		var euSign = this.m_euSign;

		try {
			var infoEx = euSign.ParseCertificateEx(cert);
			onSuccess(infoEx);
		} catch (error) {
			onError(error);
		}
	}
})(EndUser.prototype.ParseCertificateEx);

EndUser.prototype.AppendDataToSignedData = function (signedData, data, asBase64String, onSuccess, onError) {
	var pThis = this;
	var euSign = this.m_euSign;

	try {
		var signerInfo = euSign.CtxGetSignerInfo(pThis.m_context, 0, signedData);
		var signerCert = signerInfo.GetData();
		var signer = euSign.GetSigner(0, signedData);

		var newSign = euSign.CtxCreateEmptySign(pThis.m_context, pThis.m_euKSP._GetSignAlgoByCertificate(signerInfo), data, signerCert);
		signedData = euSign.AppendSigner(
			signer, signerCert,
			newSign, asBase64String);
		onSuccess(signedData);
	} catch (error) {
		onError(error);
	}

}

EndUser.prototype.AppendValidationData = function (signedData, signerCert, signAlgo, asBase64String, onSuccess, onError) {
	var pThis = this;
	var euSign = this.m_euSign;

	try {
		if (typeof signedData == 'string') {
			signedData = euSign.Base64Decode(signedData);
		}

		if (!signerCert) {
			var signerInfo = euSign.CtxGetSignerInfo(pThis.m_context, 0, signedData);
			signerCert = signerInfo.GetData();
		}

		var previousSign = euSign.CtxCreateEmptySign(
			pThis.m_context, signAlgo,
			null,
			signerCert);

		var signer = euSign.GetSigner(0, signedData);
		signer = euSign.AppendValidationDataToSigner(
			signer, signerCert);
		signedData = euSign.AppendSigner(
			signer, signerCert,
			previousSign, asBase64String);

		onSuccess(signedData);
	} catch (error) {
		onError(error);
	}
};


EndUser.prototype.GetKeyMediasKSP = function (kspSettings, authData, onSuccess, onError) {
	var pThis = this;

	if (!kspSettings || kspSettings.ksp !== EndUserKSP.EU_KSP_VTOKEN || !kspSettings.systemId) {
		setTimeout(function () {
			var error = pThis.m_euSign.MakeError(
				EU_ERROR_BAD_PARAMETER);
			onError(error);
		}, 1);
		return;
	}

	if (!authData || !authData.userName || !authData.password) {
		setTimeout(function () {
			var error = pThis.m_euSign.MakeError(
				EU_ERROR_BAD_PARAMETER);
			onError(error);
		}, 1);
		return;
	}

	var basePath = kspSettings.address;
	if (basePath.endsWith("/")) {
		basePath = basePath.substring(0, basePath.length - 1);
	}

	pThis.m_euKSP._VTokenSendRequest(basePath + "/token.auth", JSON.stringify({
		userName: authData.userName,
		password: authData.password,
		clientId: kspSettings.systemId
	}), null, function (response) {

		var token = response.tokenBody;
		var isTwoFactor = response.isTwoFactorEnable;

		pThis.m_euKSP._VTokenSendRequest(basePath + "/token.list", null, token, function (response) {
			var keys = [];

			for (var i = 0; i < response.length; i++) {
				if (!response[i].signatureKey) {
					continue;
				}

				keys.push({
					keyId: response[i].uri,
					visibleName: response[i].title + " " + response[i].signatureKey.subjectCommonName,
					subject: response[i].signatureKey.subjectCommonName,
					issuer: response[i].signatureKey.issuerCommonName,
					isStamp: response[i].signatureKey.isElectronicStamp
				});
			}

			onSuccess({
				userId: token,
				isTwoFactor,
				keys
			});
		}, onError);
	}, onError);
}

EndUser.prototype.SetTwoFactorCodeKSP = function (code, onSuccess, onError) {
	var pThis = this;

	if (!this.m_euKSP.IsPrivateKeyReaded()) {
		setTimeout(function () {
			onError(pThis.m_euSign.MakeError(EU_ERROR_BAD_CERT));
		}, 1);
		return;
	}
	var keyContext = this.m_euKSP.m_keyContext;

	if (!keyContext.authData) {
		keyContext.authData = {};
	}
	keyContext.authData.twoFactorCode = code;
	onSuccess();
}

