EndUserKSP.prototype._SignServerSendRequest = function (
	url, request, onSuccess, onError) {
	var pThis = this;

	try {
		var httpRequest = new XMLHttpRequest();

		httpRequest.onload = function () {
			if (httpRequest.readyState != 4)
				return;

			var error;

			if (httpRequest.status == 500) {
				try {
					var errorObj = JSON.parse(httpRequest.responseText);
					errorCode = parseInt(errorObj.detail.replace(/.*\(|\)$/, ""));
					error = pThis.MakeError(
						errorCode, null);
					onError(error);
				} catch (e) {
					console.error(e);
					error = pThis.MakeError(
						EU_ERROR_TRANSMIT_REQUEST, null);
					onError(error);
					return;
				}
			} else if (httpRequest.status != 200) {
				error = pThis.MakeError(
					EU_ERROR_TRANSMIT_REQUEST, null);
				onError(error);
				return;
			}

			var response = null;
			try {
				response = JSON.parse(httpRequest.responseText);
			} catch (e) {
				response = null;
			}

			if (!response) {
				error = pThis.MakeError(
					EU_ERROR_TRANSMIT_REQUEST, null);
				onError(error);
				return;
			}

			onSuccess(response);
		};

		httpRequest.onerror = function (e) {
			var error = pThis.MakeError(
				EU_ERROR_TRANSMIT_REQUEST, null);
			onError(error);
		};

		httpRequest.open("POST", url);
		httpRequest.setRequestHeader("Content-Type", "application/json");
		httpRequest.send(request);
	} catch (e) {
		var error = pThis.MakeError(
			EU_ERROR_TRANSMIT_REQUEST, null);
		onError(error);
	}
};

EndUserKSP.prototype._VTokenErrorCodes = {
	1: {
		"CIHSMVTCOBASE-1": "Невірно вказаний код двухфакторної авторизації",
		"AUTHCOMMON-14": "Невірно вказаний код двухфакторної авторизації",
		"AUTHBASE-1": "Невірно вказаний ідентифікатор користувача",
		"AUTHBASE-6": "Невівно вказаний пароль користувача",
		"CIHSMAGENTBASE-2-1": "Невірно вказаний пароль ключа"
	},
	2: {
		"CIHSMVTCOBASE-1": "Неправильно указан код двухфакторной авторизации",
		"AUTHCOMMON-14": "Неправильно указан код двухфакторной авторизации",
		"AUTHBASE-1": "Неправильно указан идентификатор пользователя",
		"AUTHBASE-6": "Неправильно указан пароль пользователя",
		"CIHSMAGENTBASE-2-1": "Неправильно указан пароль ключа"
	},
	3: {
		"CIHSMVTCOBASE-1": "Two-factor identification code is invalid",
		"AUTHCOMMON-14": "Two-factor identification code is invalid",
		"AUTHBASE-1": "User identifier is invalid",
		"AUTHBASE-6": "User password is invalid",
		"CIHSMAGENTBASE-2-1": "Private key password is invalid"
	}
}

EndUserKSP.prototype._VTokenSendRequest = function (
	url, request, token, onSuccess, onError) {
	var pThis = this;

	try {
		var httpRequest = new XMLHttpRequest();

		httpRequest.onload = function () {
			if (httpRequest.readyState != 4)
				return;

			var error;

			if (httpRequest.status == 400 || httpRequest.status == 500) {
				try {
					var errorObj = JSON.parse(httpRequest.responseText);
					console.error(errorObj.techMessage)

					var keyPasswordErrorCode = "CIHSMAGENTBASE-2-1";
					if (errorObj.techMessage.indexOf(keyPasswordErrorCode) > 0) {
						error = new EUSignCPException(keyPasswordErrorCode, pThis._VTokenErrorCodes[pThis.m_euSign.errorLangCode][keyPasswordErrorCode]);
					}
					else {
						var answerProp = "ServiceAnswer:";
						var answerPropIndex = errorObj.techMessage.indexOf(answerProp);
						if (answerPropIndex >= 0) {
							errorObj = JSON.parse(errorObj.techMessage.substring(answerPropIndex + answerProp.length));
						}
						var localizedMessage = pThis._VTokenErrorCodes[pThis.m_euSign.errorLangCode][errorObj.code];
						error = new EUSignCPException(errorObj.code, localizedMessage || errorObj.message);
					}
					setTimeout(() => {
						onError(error);
					}, 1);
					return;
				} catch (e) {
					console.error(e);
					error = pThis.MakeError(
						EU_ERROR_TRANSMIT_REQUEST, null);
					setTimeout(() => {
						onError(error);
					}, 1);
					return;
				}
			} else if (httpRequest.status != 200) {
				error = pThis.MakeError(
					EU_ERROR_TRANSMIT_REQUEST, null);
				setTimeout(() => {
					onError(error);
				}, 1);
				return;
			}

			if (httpRequest.responseText === "") {
				onSuccess();
				return;
			}

			var response = null;
			try {
				response = JSON.parse(httpRequest.responseText);
			} catch (e) {
				response = null;
			}

			if (!response) {
				error = pThis.MakeError(
					EU_ERROR_TRANSMIT_REQUEST, null);
				onError(error);
				return;
			}

			onSuccess(response);
		};

		httpRequest.onerror = function (e) {
			var error = pThis.MakeError(
				EU_ERROR_TRANSMIT_REQUEST, null);
			onError(error);
		};

		if (request) {
			httpRequest.open("POST", url);
			httpRequest.setRequestHeader("Content-Type", "application/json");
			if (token) {
				httpRequest.setRequestHeader("Authorization", "Bearer " + token);
			}
			httpRequest.send(request);
		}
		else {
			httpRequest.open("GET", url);
			httpRequest.setRequestHeader("Content-Type", "application/json");
			if (token) {
				httpRequest.setRequestHeader("Authorization", "Bearer " + token);
			}
			httpRequest.send();
		}

	} catch (e) {
		var error = pThis.MakeError(
			EU_ERROR_TRANSMIT_REQUEST, null);
		onError(error);
	}
};

EndUserKSP.prototype._VTokenCreateProtectedParams = function (url, request, token, onSuccess, onError) {
	this._VTokenSendRequest(url + "/protectedParameters/settings", null, token, function (params) {
		var pki = forge.pki;

		var key = forge.random.getBytesSync(16);
		var iv = forge.util.hexToBytes("00000000000000000000000000000000")
		var cipher = forge.cipher.createCipher('AES-CTR', key);

		cipher.start({ iv: iv });
		cipher.update(forge.util.createBuffer(request, 'utf8'));
		cipher.finish();

		var encryptedjsonObject = cipher.output;

		var buffer = forge.util.createBuffer(key, 'raw');
		buffer.putBytes(forge.util.encodeUtf8(params.currentUtcDateTime));

		var bytes = buffer.getBytes();
		var publicKey = pki.publicKeyFromPem(params.publicKeyTextual);

		var encrypted = publicKey.encrypt(bytes, 'RSA-OAEP', {
			md: forge.md.sha256.create(),
			mgf1: {
				md: forge.md.sha256.create()
			}
		});

		var data = {
			secretKey: forge.util.encode64(encrypted),
			encryptedData: forge.util.encode64(encryptedjsonObject.getBytes())
		}

		onSuccess(data);

	}, onError);
}

EndUserKSP.EU_KSP_GRYADA = -1;
EndUserKSP.EU_KSP_VTOKEN = -2;

EndUserKSP.prototype._CtxReadPrivateKeyWithServer = (function (_super) {
	return function (kspSettings, userId, getCerts, keyId, caption, authData, onSuccess, onError) {
		if (!kspSettings || (kspSettings.ksp !== EndUserKSP.EU_KSP_GRYADA && kspSettings.ksp !== EndUserKSP.EU_KSP_VTOKEN)) {
			_super.apply(this, arguments);
			return;
		}

		var pThis = this;
		var signAlgos = [EU_CTX_SIGN_DSTU4145_WITH_GOST34311];
		var certIssuerCN = null;

		var keyContext = new EndUserKSPKey(
			kspSettings, userId, keyId, signAlgos,
			pThis._GetKSPSignContainers(kspSettings),
			certIssuerCN, [], null);
		keyContext.authData = authData;

		if (!getCerts) {
			setTimeout(function () {
				onSuccess(keyContext);
			}, 1);
			return;
		}

		var hashes = [
			{
				name: "Зчитування ос. ключа",
				val: "AAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAA="
			}
		];
		var signAlgo = signAlgos[0];
		var originatorDescription = caption ?
			caption :
			SS_SERVER_ORIGINATOR_DESCRIPTION.replace("%s",
				kspSettings.systemId || s_origin);
		var operationDescription = authData ?
			authData.name :
			SS_SERVER_READ_KEY_DESCRIPTION.replace("%s",
				kspSettings.systemId || s_origin);
		var operationType = EndUserKSP.EU_KSP_OPERATION_TYPE_READ_PK;

		pThis._CtxSignHashesWithServer(keyContext,
			EndUserKSP.EU_KSP_SIGN_CONTAINER_CADES,
			EndUserKSP.EU_KSP_SIGN_FORMAT_CADES,
			EU_SIGN_TYPE_CADES_BES,
			signAlgo, hashes, operationType,
			originatorDescription, operationDescription,
			function (signatures) {
				try {
					var signedData = pThis.m_euSign.Base64Decode(signatures[0]);
					var signerInfo = pThis.m_euSign.CtxGetSignerInfo(
						pThis.m_context, 0, signedData);
					var keyContext = pThis._MakeKSPKeyContext(
						kspSettings, userId, keyId, [signerInfo.GetData()]);
					keyContext.authData = authData;

					onSuccess(keyContext);
				} catch (e) {
					pThis.ResetPrivateKey();

					onError(e);
					return;
				}
			},
			function (e) {
				pThis.ResetPrivateKey();

				onError(e);
			});

	};
})(EndUserKSP.prototype._CtxReadPrivateKeyWithServer);

EndUserKSP.prototype._CtxSignHashesWithServer = (function (_super) {
	return function (keyContext, signContainerType, signContainerSubType, signLevel, signAlgo, hashes, operationType, originatorDescription, operationDescription, onSuccess, onError) {
		var pThis = this;
		if (keyContext == null) {
			setTimeout(function () {
				var error = pThis.MakeError(
					EU_ERROR_BAD_CERT, null);
				onError(error);
			}, 1);
			return;
		}

		var kspSettings = keyContext.kspSettings;
		if (!kspSettings) {
			setTimeout(function () {
				var error = pThis.MakeError(
					EU_ERROR_BAD_PARAMETER, null);
				onError(error);
			}, 1);
			return;
		}

		if (kspSettings.ksp == EndUserKSP.EU_KSP_GRYADA) {
			var basePath = kspSettings.address;
			if (basePath.endsWith("/")) {
				basePath = basePath.substring(0, basePath.length - 1);
			}

			var hashesValues = [];

			for (var i = 0; i < hashes.length; i++) {
				var item = hashes[i];
				hashesValues.push(item.val);
			}

			if (signContainerType == EndUserKSP.EU_KSP_SIGN_CONTAINER_PADES) {
				pThis._SignServerSendRequest(basePath + "/Sign/HashPDF", JSON.stringify({
					keyName: kspSettings.systemId,
					keyPassword: "##" + keyContext.userId + "##" + keyContext.keyId,
					hashes: hashesValues
				}), onSuccess, onError);
			} else {
				pThis._SignServerSendRequest(basePath + "/Sign/HashArray", JSON.stringify({
					keyName: kspSettings.systemId,
					keyPassword: "##" + keyContext.userId + "##" + keyContext.keyId,
					hashes: hashesValues
				}), onSuccess, onError);
			}
			return;

		} else if (kspSettings.ksp == EndUserKSP.EU_KSP_VTOKEN) {

			var basePath = kspSettings.address;
			if (basePath.endsWith("/")) {
				basePath = basePath.substring(0, basePath.length - 1);
			}

			var hashesValues = [];

			for (var i = 0; i < hashes.length; i++) {
				var item = hashes[i];
				hashesValues.push(item.val);
			}

			var signParams = {
				pin: keyContext.authData.pin,
				hashAlgorithm: "GOST3411",
				signatureFormat: "CADES_T",
				embedSignerCertificate: true,
				hashesToSign: hashesValues
			};

			var sign = function () {
				pThis._VTokenCreateProtectedParams(basePath, JSON.stringify(signParams), keyContext.authData.token, function (protectedParams) {
					protectedParams.ciHsmTokenUri = keyContext.keyId;
					pThis._VTokenSendRequest(basePath + "/es.create/hash", JSON.stringify(protectedParams), keyContext.authData.token, onSuccess, onError);
				}, onError);
			}

			if (!!keyContext.authData.twoFactorCode) {
				pThis._VTokenSendRequest(basePath + "/permission.2f", JSON.stringify({
					ciHsmTokenUri: keyContext.keyId,
					operationType: "SIGNING"
				}), keyContext.authData.token, function () {

					pThis._VTokenSendRequest(basePath + "/permission", JSON.stringify({
						ciHsmTokenUri: keyContext.keyId,
						operationType: "SIGNING",
						twoFactorCode: keyContext.authData.twoFactorCode
					}), keyContext.authData.token, function () {

						keyContext.authData.twoFactorCode = null;
						sign();

					}, onError);

				}, onError);
			}
			else {
				sign();
			}
		} else {
			_super.apply(this, arguments);
			return;
		}
	};
})(EndUserKSP.prototype._CtxSignHashesWithServer);

