EndUserKSP.prototype._SendRequest = function (
	url, request, onSuccess, onError) {
	var pThis = this;

	var ksp = pThis.m_KSPs.find(ksp => url.includes(ksp.address))
	var proxy = ksp && !ksp.directAccess;

	try {
		var httpRequest = new XMLHttpRequest();
		httpRequest.onload = function () {
			if (httpRequest.readyState != 4)
				return;

			var error;

			if (httpRequest.status != 200) {
				error = pThis.MakeError(
					EU_ERROR_TRANSMIT_REQUEST, null);
				onError(error);
				return;
			}

			var response = null;
			try {
				if (proxy) {
					var data = ArrayToString(pThis.m_euSign.Base64Decode(httpRequest.responseText));
					response = JSON.parse(data);
				} else {
					response = JSON.parse(httpRequest.responseText);
				}
			} catch (e) {
				response = null;
			}

			if (!response) {
				error = pThis.MakeError(
					EU_ERROR_TRANSMIT_REQUEST, null);
				onError(error);
				return;
			}

			onSuccess(response);
		};

		httpRequest.onerror = function (e) {
			var error = pThis.MakeError(
				EU_ERROR_TRANSMIT_REQUEST, null);
			onError(error);
		};

		if (proxy) {
			var dataBase64 = pThis.m_euSign.Base64Encode(StringToArray(request));

			httpRequest.open("POST", XMLHTTPProxyService + "?address=" + url);
			httpRequest.setRequestHeader("Content-Type", "X-user/base64-data");
			httpRequest.send(dataBase64);
		} else {
			httpRequest.open("POST", url);
			httpRequest.setRequestHeader("Content-Type", "application/json");
			httpRequest.send(request);
		}
	} catch (e) {
		var error = pThis.MakeError(
			EU_ERROR_TRANSMIT_REQUEST, null);
		onError(error);
	}
};

